mapper.select:
SELECT CODE AS cate_code, code_name cate_name, etc1 AS cate_sp, use_yn, (SELECT b.code_name FROM tb_pmb_plan_tag_category a, tb_cmm_code b WHERE cate_id =a.code AND a.tag_id = b.code AND b.code_group = 'plan_tag_code' ORDER BY b.order_no LIMIT 1 ) tag_name, (SELECT count(b.code) FROM tb_pmb_plan_tag_category a, tb_cmm_code b WHERE cate_id =a.code AND a.tag_id = b.code AND b.code_group = 'plan_tag_code' ) tag_count, ( SELECT COUNT(1) FROM tb_pmb_plan_list WHERE sale_status = 1 AND disp_yn = 1 AND (plan_tag1 IN (SELECT b.code FROM tb_pmb_plan_tag_category a, tb_cmm_code b WHERE cate_id =a.code AND a.tag_id = b.code AND b.code_group = 'plan_tag_code' and b.use_yn = 'Y') OR plan_tag2 IN (SELECT b.code FROM tb_pmb_plan_tag_category a, tb_cmm_code b WHERE cate_id =a.code AND a.tag_id = b.code AND b.code_group = 'plan_tag_code' and b.use_yn = 'Y') OR plan_tag3 IN (SELECT b.code FROM tb_pmb_plan_tag_category a, tb_cmm_code b WHERE cate_id =a.code AND a.tag_id = b.code AND b.code_group = 'plan_tag_code' and b.use_yn = 'Y') OR plan_tag4 IN (SELECT b.code FROM tb_pmb_plan_tag_category a, tb_cmm_code b WHERE cate_id =a.code AND a.tag_id = b.code AND b.code_group = 'plan_tag_code' and b.use_yn = 'Y') OR plan_tag5 IN (SELECT b.code FROM tb_pmb_plan_tag_category a, tb_cmm_code b WHERE cate_id =a.code AND a.tag_id = b.code AND b.code_group = 'plan_tag_code' and b.use_yn = 'Y') ) ) plan_cnt, order_no FROM tb_cmm_code a WHERE code_group = 'plan_tag_code_group'
AND etc1 = #{searchCateGroupSp}
ORDER BY order_no,code

mapper.delete:
DELETE FROM tb_cmm_code
WHERE code_group = #{codeGroup}
AND code=#{code}
